/**
 * Scan-axis benchmark for wide varint decoding and LMDB skip-scan selectivity. The fixed one-million-row store keeps
 * each comparison's working set stable while {@link #valuesPerPredicate} selects 10%, 1%, or 0.1% of every predicate
 * run. All stored IDs require the wide varint decoder.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 3, time = 1, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode(Mode.AverageTime)
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx3G" })
@Measurement(iterations = 5, time = 1, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class ScanBenchmark {

	private static final int ROWS = 1_000_000;
	private static final int BATCH_ROWS = 1_024;
	private static final long WIDE_BASE = 1L << 50;
	private static final long SUBJECT = WIDE_BASE + 1;
	private static final long CONTEXT = WIDE_BASE + 2;
	private static final long PREDICATE_BASE = WIDE_BASE + 10_000;
	private static final long OBJECT_BASE = WIDE_BASE + 1_000_000;

	/** Values in each predicate run: 10, 100, and 1,000 give 10%, 1%, and 0.1% probes. */
	@Param({ "10", "100", "1000" })
	public int valuesPerPredicate;

	private File dataDir;
	private TripleStore tripleStore;
	private int predicateCount;
	private long selectedObject;
	private ByteBuffer encodedWideIds;
	private long encodedWideIdsAddress;
	private int[] encodedWideIdOffsets;

	@Setup(Level.Trial)
	public void setUp() throws IOException {
		dataDir = Files.newTemporaryFolder();
		tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc"), null);
		predicateCount = ROWS / valuesPerPredicate;
		selectedObject = OBJECT_BASE + valuesPerPredicate / 2L;
		tripleStore.startTransaction();
		for (int predicate = 0; predicate < predicateCount; predicate++) {
			long predicateId = PREDICATE_BASE + predicate;
			for (int value = 0; value < valuesPerPredicate; value++) {
				tripleStore.storeTriple(SUBJECT, predicateId, OBJECT_BASE + value, CONTEXT, true);
			}
		}
		tripleStore.commit();

		encodedWideIds = MemoryUtil.memAlloc(ROWS * 9);
		encodedWideIdOffsets = new int[ROWS];
		for (int row = 0; row < ROWS; row++) {
			encodedWideIdOffsets[row] = encodedWideIds.position();
			Varint.writeUnsigned(encodedWideIds, OBJECT_BASE + row);
		}
		encodedWideIds.flip();
		encodedWideIdsAddress = MemoryUtil.memAddress(encodedWideIds);
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		MemoryUtil.memFree(encodedWideIds);
		tripleStore.close();
		LmdbTestUtil.deleteDir(dataDir);
	}

	/** Exact-width native loads introduced by the wide-varint decoder optimization. */
	@Benchmark
	public long wideVarintDecode() {
		long digest = 0L;
		for (int offset : encodedWideIdOffsets) {
			digest = Long.rotateLeft(digest, 7) ^ Varint.readUnsigned(encodedWideIdsAddress + offset);
		}
		return digest;
	}

	/** Test-local copy of the former byte-at-a-time decoder, retained solely as the paired JMH baseline. */
	@Benchmark
	public long legacyWideVarintDecodeBaseline() {
		long digest = 0L;
		for (int offset : encodedWideIdOffsets) {
			digest = Long.rotateLeft(digest, 7) ^ readUnsignedByteAtATime(encodedWideIdsAddress + offset);
		}
		return digest;
	}

	/** Decodes the complete wide-ID keyspace through the bulk iterator API. */
	@Benchmark
	public long fullScanDecode() throws IOException {
		long[] batch = new long[BATCH_ROWS * 4];
		long rows = 0L;
		long digest = 0L;
		try (TxnManager.Txn txn = tripleStore.getTxnManager().createReadTxn();
				RecordIterator iterator = tripleStore.getTriples(txn, -1L, -1L, -1L, -1L, true)) {
			int filled;
			while ((filled = iterator.fill(batch, BATCH_ROWS)) != 0) {
				rows += filled;
				for (int row = 0; row < filled; row++) {
					digest = Long.rotateLeft(digest, 7) ^ batch[row * 4 + TripleIndex.OBJ_IDX];
				}
			}
		}
		if (rows != ROWS) {
			throw new IllegalStateException("expected " + ROWS + " decoded rows but got " + rows);
		}
		return digest ^ rows;
	}

	/** Probes one object in every predicate run, exercising skip-scan at the configured density. */
	@Benchmark
	public long skipScanDensity() throws IOException {
		long rows = 0L;
		long digest = 0L;
		try (TxnManager.Txn txn = tripleStore.getTxnManager().createReadTxn();
				RecordIterator iterator = tripleStore.getTriples(txn, SUBJECT, -1L, selectedObject, CONTEXT, true)) {
			long[] quad;
			while ((quad = iterator.next()) != null) {
				rows++;
				digest = Long.rotateLeft(digest, 7) ^ quad[TripleIndex.PRED_IDX];
			}
		}
		if (rows != predicateCount) {
			throw new IllegalStateException("expected " + predicateCount + " selected rows but got " + rows);
		}
		return digest ^ rows;
	}

	static long readUnsignedByteAtATime(long address) {
		int first = LmdbUtil.getByte(address) & 0xFF;
		if (first <= 240) {
			return first;
		}
		if (first <= 248) {
			return 240L + ((long) (first - 241) << 8) + (LmdbUtil.getByte(address + 1) & 0xFFL);
		}
		if (first == 249) {
			return 2288L + ((LmdbUtil.getByte(address + 1) & 0xFFL) << 8)
					+ (LmdbUtil.getByte(address + 2) & 0xFFL);
		}
		int bytes = first - 247;
		long value = 0L;
		for (int byteIndex = 1; byteIndex <= bytes; byteIndex++) {
			value = (value << 8) | (LmdbUtil.getByte(address + byteIndex) & 0xFFL);
		}
		return value;
	}
}
